  @fn paletteTrackLabel(focusedTrack)  @ 618-623
  @fn openRenameModal(trackIdx, slotIdx, currentName)  @ 625-632
  @fn openDeleteModal(trackIdx, slot)  @ 634-643
  @fn renderPaletteActions(focusedTrack, focusedSlot)  @ 683-698
  @fn renderPaletteList(slots)  @ 702-733
      -- Three columns: key (monospace — hotkey), kind glyph, name (UI font).
      -- Selectable in col 0 with SpanAllColumns; key text painted on top via SameLine.
  @fn renderPaletteBody(focusedTrack)  @ 735-741

